# Shape hierarchy with interface and abstract base
interface Drawable:
    def draw() -> str

@abstract
class Shape:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    @virtual
    def area(self) -> float:
        return 0.0

    @virtual
    def describe(self) -> str:
        return "Shape"

    def position(self) -> str:
        return f"({self.x}, {self.y})"

class Circle(Shape):
    radius: float

    def __init__(self, x: float, y: float, radius: float):
        super().__init__(x, y)
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def describe(self) -> str:
        return f"Circle(r={self.radius})"

class Rectangle(Shape, Drawable):
    width: float
    height: float

    def __init__(self, x: float, y: float, width: float, height: float):
        super().__init__(x, y)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def describe(self) -> str:
        return f"Rectangle({self.width}x{self.height})"

    def draw(self) -> str:
        return f"Drawing rectangle at {self.position()}"

