# Geometry utilities with struct and functions
from shapes import Shape

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_to(self, other: Point) -> float:
        dx: float = self.x - other.x
        dy: float = self.y - other.y
        return (dx * dx + dy * dy) ** 0.5

class BoundingBox:
    min_x: float
    min_y: float
    max_x: float
    max_y: float

    def __init__(self, min_x: float, min_y: float, max_x: float, max_y: float):
        self.min_x = min_x
        self.min_y = min_y
        self.max_x = max_x
        self.max_y = max_y

    def contains(self, p: Point) -> bool:
        return self.min_x <= p.x <= self.max_x and self.min_y <= p.y <= self.max_y

    def area(self) -> float:
        return (self.max_x - self.min_x) * (self.max_y - self.min_y)

def enclosing_box(shapes_list: list[Shape]) -> BoundingBox:
    if len(shapes_list) == 0:
        return BoundingBox(0.0, 0.0, 0.0, 0.0)

    min_x: float = shapes_list[0].x
    min_y: float = shapes_list[0].y
    max_x: float = shapes_list[0].x
    max_y: float = shapes_list[0].y

    for s in shapes_list:
        if s.x < min_x:
            min_x = s.x
        if s.y < min_y:
            min_y = s.y
        if s.x > max_x:
            max_x = s.x
        if s.y > max_y:
            max_y = s.y

    return BoundingBox(min_x, min_y, max_x, max_y)
